                                     int init) {
        data[start] += init;
        int sz0 = length / 4 * 4;
        int i = 1;
        if (sz0 >= 4) {
        	long a = data[start];
                for (; i < sz0 - 4; i += 4) {
                        a = data[start + i] += a;
                        a = data[start + i + 1] += a;
                        a = data[start + i + 2] += a;
                        a = data[start + i + 3] += a;
                }
        }

        for (; i != length; ++i) {
                data[start + i] += data[start + i - 1];
        }
        return data[start + length - 1];
}

